import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const YPilotService = {
  async getResponse(prompt: string, context?: string) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: "You are Y-Pilot, the Digital Concierge for 'Y', the African Super-App. You are culturally intelligent, understand Liberian and Pan-African slang, business etiquette, and are professional yet warm. You help users summarize news, draft messages, and track spending.",
          temperature: 0.7,
        },
      });
      return response.text;
    } catch (error) {
      console.error("Y-Pilot Error:", error);
      return "I'm having a bit of a connection issue, but Y-Pilot is still here for you. How can I assist?";
    }
  },

  async translateMessage(text: string, targetLang: string = 'English') {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Translate this message to ${targetLang}: "${text}". Only provide the translated text.`,
      });
      return response.text;
    } catch (error) {
      return text;
    }
  },

  async transcribeAudio(dummyAudioData?: string) {
    // Simulating transcription for this demo as we don't have real-time audio streams here
    return "This is a simulated transcription of your voice note.";
  }
};

import React from 'react';
