import React, { useState } from 'react';
import { Send, Mic, ShieldCheck, MoreHorizontal, User } from './Icons';
import { COLORS } from '../constants';
import { Message } from '../types';
import { YPilotService } from '../services/gemini';

const MOCK_MESSAGES: Message[] = [
  { id: '1', senderId: 'friend', text: 'Hey, are you going to the Tech Summit in Monrovia tomorrow?', timestamp: new Date() },
  { id: '2', senderId: 'me', text: 'Yeah, just bought my ticket on Y!', timestamp: new Date() },
  { id: '3', senderId: 'friend', text: 'Salut, pourrais-tu m\'aider à traduire ce document?', timestamp: new Date() },
];

const Chat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>(MOCK_MESSAGES);
  const [inputValue, setInputValue] = useState('');
  const [isTranslating, setIsTranslating] = useState<string | null>(null);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const newMessage: Message = {
      id: Date.now().toString(),
      senderId: 'me',
      text: inputValue,
      timestamp: new Date(),
    };
    setMessages([...messages, newMessage]);
    setInputValue('');
  };

  const translateMsg = async (id: string, text: string) => {
    setIsTranslating(id);
    const translated = await YPilotService.translateMessage(text);
    setMessages(prev => prev.map(m => m.id === id ? { ...m, translatedText: translated } : m));
    setIsTranslating(null);
  };

  return (
    <div className="flex flex-col h-full bg-[#0B0B0B]">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-white/5 bg-[#111]">
        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 rounded-full bg-indigo-600 flex items-center justify-center font-bold">J</div>
          <div>
            <div className="font-bold">Josephine B.</div>
            <div className="text-[10px] text-green-500 flex items-center"><ShieldCheck size={10} className="mr-1" /> Encrypted</div>
          </div>
        </div>
        <button className="p-2"><MoreHorizontal /></button>
      </div>

      {/* Message Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m) => {
          const isMe = m.senderId === 'me';
          return (
            <div key={m.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] space-y-1`}>
                <div className={`p-4 rounded-2xl ${
                  isMe ? 'bg-indigo-700 text-white rounded-tr-none' : 'bg-[#1A1A1A] text-white rounded-tl-none'
                }`}>
                  <p className="text-sm">{m.text}</p>
                  {m.translatedText && (
                    <div className="mt-2 pt-2 border-t border-white/10 italic text-xs text-indigo-200">
                      {m.translatedText}
                    </div>
                  )}
                </div>
                {!isMe && !m.translatedText && (
                  <button 
                    onClick={() => translateMsg(m.id, m.text)}
                    disabled={isTranslating === m.id}
                    className="text-[10px] text-indigo-400 font-bold uppercase tracking-wider px-2"
                  >
                    {isTranslating === m.id ? 'Translating...' : 'Auto-Translate'}
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-[#111] border-t border-white/5">
        <div className="flex items-center space-x-2 bg-[#1A1A1A] p-2 rounded-2xl border border-white/5">
          <button className="p-2 text-gray-400"><Mic size={20} /></button>
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your message..."
            className="flex-1 bg-transparent border-none focus:outline-none text-sm placeholder:text-gray-600"
          />
          <button 
            onClick={handleSend}
            className="p-2 bg-indigo-600 rounded-xl text-white disabled:opacity-50"
            disabled={!inputValue.trim()}
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default Chat;

