import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, Send, Mic, MoreHorizontal, ChevronRight } from './Icons';
import { COLORS } from '../constants';
import { YPilotService } from '../services/gemini';

const YPilot: React.FC = () => {
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; text: string }[]>([
    { role: 'assistant', text: "Hello! I'm Y-Pilot, your Digital Concierge. I'm here to help you navigate Y, summarize news, or track your spending. How can I assist you today?" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);

    setIsTyping(true);
    const aiResponse = await YPilotService.getResponse(userMsg);
    setMessages(prev => [...prev, { role: 'assistant', text: aiResponse }]);
    setIsTyping(false);
  };

  return (
    <div className="flex flex-col h-full relative">
      {/* Background decoration */}
      <div className="absolute inset-0 bg-gradient-to-b from-indigo-900/10 via-transparent to-transparent pointer-events-none"></div>

      {/* Header */}
      <div className="p-6 border-b border-white/5 bg-[#0B0B0B]/50 backdrop-blur-md">
        <div className="flex items-center space-x-3">
          <div className="p-3 bg-indigo-600 rounded-2xl shadow-lg shadow-indigo-600/30">
            <Sparkles size={24} className="text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black">Y-Pilot</h1>
            <div className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400">Digital Concierge</div>
          </div>
        </div>
      </div>

      {/* Chat Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-5 rounded-3xl ${
              m.role === 'user' 
              ? 'bg-[#1A1A1A] text-white rounded-tr-none border border-white/5' 
              : 'bg-indigo-900/40 text-white rounded-tl-none border border-indigo-500/20'
            }`}>
              <p className="text-sm leading-relaxed">{m.text}</p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
             <div className="bg-indigo-900/20 px-6 py-4 rounded-3xl border border-indigo-500/10 animate-pulse text-indigo-300 text-xs font-bold uppercase tracking-widest">
                Thinking...
             </div>
          </div>
        )}
      </div>

      {/* Quick Actions */}
      <div className="px-6 py-2 flex space-x-2 overflow-x-auto scrollbar-hide">
        {["Summarize News", "Draft Message", "Wallet Status"].map(action => (
          <button 
            key={action}
            onClick={() => setInput(action)}
            className="px-4 py-2 bg-white/5 border border-white/10 rounded-full text-xs font-bold whitespace-nowrap text-gray-400 hover:text-white transition-colors"
          >
            {action}
          </button>
        ))}
      </div>

      {/* Input */}
      <div className="p-6">
        <div className="bg-[#111] p-2 rounded-3xl border border-white/10 shadow-2xl flex items-center space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask Y-Pilot anything..."
            className="flex-1 bg-transparent px-4 py-3 text-sm focus:outline-none placeholder:text-gray-600"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-4 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-600/20 text-white hover:bg-indigo-500 disabled:opacity-50 transition-all"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default YPilot;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Feed from './components/Feed';
import Chat from './components/Chat';
import Gathering from './components/Gathering';
import Wallet from './components/Wallet';
import YPilot from './components/YPilot';
import { Module } from './types';

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<Module>('feed');

  const renderModule = () => {
    switch (activeModule) {
      case 'feed':
        return <Feed />;
      case 'chat':
        return <Chat />;
      case 'gathering':
        return <Gathering />;
      case 'wallet':
        return <Wallet />;
      case 'ypilot':
        return <YPilot />;
      default:
        return <Feed />;
    }
  };

  return (
    <Layout activeModule={activeModule} setActiveModule={setActiveModule}>
      <div className="max-w-3xl mx-auto h-full">
        {renderModule()}
      </div>
    </Layout>
  );
};

export default App;

