import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, Send, Mic, MoreHorizontal, ShieldCheck, Globe, Search } from './Icons';
import { COLORS, EKAN_GRADIENT_CSS } from '../constants';
import { EKANPilotService } from '../services/gemini';

const Pilot: React.FC = () => {
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; text: string }[]>([
    { role: 'assistant', text: "Hello! I'm EKAN-Pilot, your Digital Concierge. I can help you bridge the language gap, summarize your feed, and secure your transactions. How can I assist you?" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages]);

  const handleSend = async (overrideInput?: string) => {
    const textToSend = overrideInput || input;
    if (!textToSend.trim() || isTyping) return;

    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: textToSend }]);

    setIsTyping(true);
    const aiResponse = await EKANPilotService.getResponse(textToSend);
    setMessages(prev => [...prev, { role: 'assistant', text: aiResponse }]);
    setIsTyping(false);
  };

  return (
    <div className="flex flex-col h-full relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute inset-0 bg-gradient-to-b from-red-600/5 via-gold-600/5 to-green-600/5 pointer-events-none"></div>

      {/* Header */}
      <div className="p-8 border-b border-white/5 bg-[#0B0B0B]/80 backdrop-blur-2xl z-10">
        <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
                <div className={`p-4 bg-gradient-to-br ${EKAN_GRADIENT_CSS} rounded-[1.8rem] shadow-2xl shadow-red-600/20`}>
                    <Sparkles size={28} className="text-black" />
                </div>
                <div>
                    <h1 className="text-3xl font-black tracking-tighter">EKAN-Pilot</h1>
                    <div className="flex items-center space-x-3">
                        <div className="text-[10px] font-black uppercase tracking-[0.4em] text-gold opacity-80">Concierge Engine</div>
                        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                    </div>
                </div>
            </div>
            <button className="p-3 bg-white/5 rounded-2xl text-gray-500 hover:text-white transition-colors"><MoreHorizontal /></button>
        </div>
      </div>

      {/* Chat Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-10 z-10 scrollbar-hide">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
            <div className={`max-w-[85%] p-7 rounded-[2.5rem] shadow-2xl ${
              m.role === 'user' 
              ? 'bg-[#1A1A1A] text-white rounded-tr-none border border-white/5' 
              : 'bg-indigo-900/30 text-white rounded-tl-none border border-indigo-500/10 backdrop-blur-2xl'
            }`}>
              <p className="text-[16px] leading-relaxed font-medium">{m.text}</p>
              {m.role === 'assistant' && (
                  <div className="mt-6 pt-6 border-t border-white/5 flex items-center justify-between">
                      <div className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-300 flex items-center">
                          <ShieldCheck size={14} className="mr-2" /> AI Verified Logic
                      </div>
                  </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
             <div className="bg-white/5 px-8 py-5 rounded-[2rem] border border-white/10 flex items-center space-x-3">
                <div className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce [animation-delay:0.4s]"></div>
                <span className="text-[11px] font-black uppercase tracking-[0.3em] text-gray-500 ml-3">Synthesizing...</span>
             </div>
          </div>
        )}
      </div>

      {/* Action Tray */}
      <div className="p-8 pt-0 z-10 space-y-6">
        <div className="flex space-x-3 overflow-x-auto scrollbar-hide py-2">
            {[
                { label: "Summarize Feed", icon: Sparkles },
                { label: "Verify Marketplace", icon: ShieldCheck },
                { label: "Global Translate", icon: Globe },
                { label: "Local Search", icon: Search }
            ].map(action => (
                <button 
                    key={action.label}
                    onClick={() => handleSend(action.label)}
                    className="flex items-center space-x-3 px-6 py-3 bg-white/5 border border-white/10 rounded-full text-[10px] font-black uppercase tracking-[0.3em] text-gray-400 hover:text-white hover:bg-white/10 transition-all whitespace-nowrap shadow-xl"
                >
                    <action.icon size={16} />
                    <span>{action.label}</span>
                </button>
            ))}
        </div>

        <div className="bg-[#111] p-3 rounded-[3rem] border border-white/10 shadow-2xl flex items-center space-x-3 group focus-within:border-gold/30 transition-all">
          <button className="p-5 text-gray-600 hover:text-gold transition-colors"><Mic size={28} /></button>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your instruction..."
            className="flex-1 bg-transparent px-2 py-4 text-base font-medium focus:outline-none placeholder:text-gray-800"
          />
          <button 
            onClick={() => handleSend()}
