    setTimeout(() => setLocation('Monrovia, Liberia'), 1500);
  }, []);

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) return;
    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto-focus next input
    if (value && index < 5) {
      const nextInput = document.getElementById(`otp-${index + 1}`);
      nextInput?.focus();
    }
  };

  const verifyOtp = () => {
    if (otp.join('').length === 6) {
      setStep('success');
      setTimeout(() => onLogin('Sam'), 2000);
    }
  };

  const glassStyle = "bg-white/5 backdrop-blur-2xl border border-white/10 shadow-[0_8px_32px_0_rgba(0,0,0,0.8)]";

  return (
    <div className="fixed inset-0 z-[100] bg-[#050505] flex items-center justify-center p-6 overflow-hidden">
      {/* Background Glows */}
      <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-red-600/10 blur-[150px] rounded-full"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-green-600/10 blur-[150px] rounded-full"></div>
      <div className="absolute top-[20%] right-[10%] w-[30%] h-[30%] bg-gold/10 blur-[120px] rounded-full"></div>

      <div className={`w-full max-w-md p-10 rounded-[3.5rem] ${glassStyle} relative z-10 transition-all duration-500`}>
        {step === 'welcome' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
            <div className="space-y-2">
              <div className={`w-16 h-16 rounded-3xl bg-gradient-to-br ${EKAN_GRADIENT_CSS} flex items-center justify-center shadow-2xl shadow-red-600/20 mb-6`}>
                <span className="text-3xl font-black text-black">E</span>
              </div>
              <h1 className="text-4xl font-black tracking-tighter leading-tight">Connect with <br/><span className="text-gold">Your World.</span></h1>
              <p className="text-sm text-gray-500 font-medium">{location} detected. Localizing experience...</p>
            </div>

            <div className="space-y-3">
              <button onClick={() => setStep('email')} className="w-full py-4 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center space-x-3 hover:scale-[1.02] transition-all">
                <Mail size={18} /> <span>Continue with Email</span>
              </button>

              <div className="grid grid-cols-2 gap-3">
                <button className="py-4 bg-white/5 border border-white/10 rounded-2xl flex items-center justify-center space-x-2 text-[10px] font-black uppercase tracking-widest hover:bg-white/10 transition-all">
                  <MessageCircle size={16} className="text-green-500" /> <span>WhatsApp</span>
                </button>
                <button className="py-4 bg-white/5 border border-white/10 rounded-2xl flex items-center justify-center space-x-2 text-[10px] font-black uppercase tracking-widest hover:bg-white/10 transition-all">
                  <Globe size={16} className="text-blue-500" /> <span>WeChat</span>
                </button>
              </div>
            </div>

            <p className="text-[10px] text-gray-600 text-center uppercase tracking-widest font-bold">
              Securely bridging <span className="text-red-500">Africa</span> to the <span className="text-green-500">Global</span> grid.
            </p>
          </div>
        )}

        {step === 'email' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
            <button onClick={() => setStep('welcome')} className="text-gray-500 hover:text-white text-xs font-black uppercase tracking-widest">Back</button>
            <div className="space-y-2">
              <h2 className="text-3xl font-black tracking-tighter">Enter Email</h2>
              <p className="text-sm text-gray-500">We'll send a 6-digit verification code.</p>
            </div>
            <div className="space-y-4">
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600" size={20} />
                <input 
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="name@example.com"
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-sm focus:outline-none focus:border-gold/50 transition-all"
                />
              </div>
              <button 
                onClick={() => setStep('otp')}
                disabled={!email.includes('@')}
                className={`w-full py-4 bg-gradient-to-r ${EKAN_GRADIENT_CSS} text-black rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center space-x-3 shadow-xl shadow-red-600/20 disabled:opacity-50 transition-all`}
              >
                <span>Send Code</span> <ArrowRight size={18} />
              </button>
            </div>
          </div>
        )}

        {step === 'otp' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
