              <h2 className="text-3xl font-black tracking-tighter">Verification</h2>
              <p className="text-sm text-gray-500">Sent to {email}</p>
            </div>
            <div className="space-y-6">
              <div className="flex justify-between gap-2">
                {otp.map((digit, i) => (
                  <input
                    key={i}
                    id={`otp-${i}`}
                    type="text"
                    maxLength={1}
                    value={digit}
                    onChange={(e) => handleOtpChange(i, e.target.value)}
                    className="w-12 h-14 bg-white/5 border border-white/10 rounded-xl text-center text-xl font-black focus:outline-none focus:border-gold/50 transition-all"
                  />
                ))}
              </div>
              <button 
                onClick={verifyOtp}
                disabled={otp.join('').length < 6}
                className={`w-full py-4 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl disabled:opacity-50 transition-all`}
              >
                Verify & Sign In
              </button>
            </div>
          </div>
        )}

        {step === 'success' && (
          <div className="py-12 flex flex-col items-center space-y-6 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 rounded-full bg-green-500/20 border-2 border-green-500 flex items-center justify-center text-green-500">
              <ShieldCheck size={48} className="animate-pulse" />
            </div>
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black tracking-tighter">Verified</h2>
              <p className="text-sm text-gray-500 font-medium">Welcome to EKAN Social Connect, Sam.</p>
