            <div className="w-full h-1 bg-white/10 rounded-full overflow-hidden">
               <div className={`h-full bg-gradient-to-r ${EKAN_GRADIENT_CSS} w-full origin-left animate-[loading_2s_ease-in-out]`}></div>
