import React, { useState } from 'react';
import Layout from './components/Layout';
import Feed from './components/Feed';
import Chat from './components/Chat';
import Gathering from './components/Gathering';
import Wallet from './components/Wallet';
import Pilot from './components/Pilot';
import Profile from './components/Profile';
import Scanner from './components/Scanner';
import Auth from './components/Auth';
import { Module } from './types';

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<Module>('feed');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userName, setUserName] = useState('');

  const handleLogin = (name: string) => {
    setUserName(name);
    setIsLoggedIn(true);
  };

  const renderModule = () => {
    switch (activeModule) {
      case 'feed':
        return <Feed />;
      case 'chat':
        return <Chat />;
      case 'gathering':
        return <Gathering />;
      case 'wallet':
        return <Wallet />;
      case 'pilot':
        return <Pilot />;
      case 'profile':
        return <Profile />;
      case 'scanner':
        return <Scanner />;
      default:
        return <Feed />;
    }
  };

  return (
    <>
      {!isLoggedIn ? (
        <Auth onLogin={handleLogin} />
      ) : (
        <Layout activeModule={activeModule} setActiveModule={setActiveModule}>
          <div className="max-w-3xl mx-auto h-full border-x border-white/5 bg-[#050505]/40 backdrop-blur-3xl shadow-2xl">
            {renderModule()}
          </div>
        </Layout>
      )}
    </>
  );
};

export default App;

