        { 
          id: 'welcome', 
          senderId: 'friend', 
          type: 'text',
          text: `Hi! I saw we share interests in ${activePartner.interests?.join(', ')}. Let's connect!`, 
          timestamp: new Date(),
          status: 'read'
        }
      ]);
    } else {
      setView('list');
      setCurrentThread(null);
