export type Module = 'feed' | 'chat' | 'gathering' | 'wallet' | 'pilot' | 'profile' | 'scanner';

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  handle: string;
  avatar: string;
  location: string;
  bio: string;
  interests: string[];
  balance: number;
  joinedAt: string;
  isVerified: boolean;
  trustScore: number; // Unique Grid Trust Score
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  location: string;
  bio?: string;
  status?: string;
  interests?: string[];
  languages?: string[];
  posts?: Post[];
}

export interface Post {
  id: string;
  thumbnail: string;
  likes: number;
  authorName?: string;
  content?: string;
  timestamp: string;
}

export interface Story {
  id: string;
  content: string; // URL or base64
  type: 'image' | 'video';
  timestamp: Date;
}

export interface UserStory {
  userId: string;
  userName: string;
  userAvatar: string;
  stories: Story[];
  hasUnseen: boolean;
}

export type MessageType = 'text' | 'image' | 'video' | 'file' | 'money';

export interface Message {
  id: string;
  senderId: string;
  text?: string;
  type: MessageType;
  mediaUrl?: string;
  fileName?: string;
  amount?: number;
  timestamp: Date;
  translatedText?: string;
  isVoice?: boolean;
  status?: 'sent' | 'delivered' | 'read';
}

export interface ChatThread {
  id: string;
  partner: User;
  lastMessage: string;
  timestamp: Date;
  unreadCount: number;
  online?: boolean;
}

export interface NewsItem {
  id: string;
  title: string;
  source: string;
  content: string;
  image: string;
  category: 'Local' | 'Global';
  timestamp: string;
  likes?: number;
}

export interface Event {
  id: string;
  title: string;
  date: string;
  location: string;
  type: 'Professional' | 'Social';
  price: number;
  image: string;
  isTicketed: boolean;
  hasGroupChat?: boolean;
}

export interface GroupVault {
  id: string;
  title: string;
  targetAmount: number;
  currentAmount: number;
  contributors: number;
  deadline: string;
}

export interface Transaction {
  id: string;
  amount: number;
  type: 'inbound' | 'outbound';
  description: string;
  status: 'completed' | 'pending';
  isEscrow?: boolean;
  timestamp: Date;
}

export interface LocalizationData {
  city: string;
  country: string;
  language: string;
  flag: string;
  greeting: string;
}

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Feed from './components/Feed';
import Chat from './components/Chat';
import Gathering from './components/Gathering';
import Wallet from './components/Wallet';
import Pilot from './components/Pilot';
import Profile from './components/Profile';
import Scanner from './components/Scanner';
import Auth from './components/Auth';
import { Module, User as UserType, UserProfile, Post, UserStory, Message, ChatThread } from './types';

const INITIAL_USER: UserProfile = {
  id: 'user_me',
  name: '',
  email: '',
  handle: '',
  avatar: 'https://picsum.photos/seed/me/200/200',
  location: 'Monrovia, Liberia',
  bio: 'Bridging communities via the Pan-African Grid.',
  interests: [],
  balance: 0.00,
  joinedAt: new Date().toISOString(),
  isVerified: true,
  trustScore: 98
};

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<Module>('feed');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState<UserProfile>(INITIAL_USER);
  const [activeChatPartner, setActiveChatPartner] = useState<UserType | null>(null);

  // Global State for Mock Persistence
  const [posts, setPosts] = useState<Post[]>([]);
  const [stories, setStories] = useState<UserStory[]>([]);
  const [messagesByThread, setMessagesByThread] = useState<Record<string, Message[]>>({});
  const [friends, setFriends] = useState<UserType[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('ekan_user_session');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setUser(parsed);
        setIsLoggedIn(true);
      } catch (e) {
        console.error("Failed to restore session");
      }
    }
  }, []);

  const handleOnboardingComplete = (data: { name: string; email: string; interests: string[] }) => {
    const newUser = {
      ...user,
      name: data.name,
      email: data.email,
      handle: `@${data.name.toLowerCase().replace(/\s+/g, '_')}`,
      interests: data.interests,
      balance: 250.00 // Welcome bonus
    };
    setUser(newUser);
    setIsLoggedIn(true);
    localStorage.setItem('ekan_user_session', JSON.stringify(newUser));
  };

  const updateBalance = (amount: number) => {
    setUser(prev => {
      const updated = { ...prev, balance: prev.balance + amount };
      localStorage.setItem('ekan_user_session', JSON.stringify(updated));
      return updated;
    });
  };

  const handleAddPost = (content: string) => {
    const newPost: Post = {
      id: Date.now().toString(),
      thumbnail: 'https://picsum.photos/seed/' + Math.random() + '/800/600',
      likes: 0,
      authorName: user.name,
      content,
      timestamp: 'Just now'
    };
    setPosts([newPost, ...posts]);
  };

  const handleStartChat = (targetUser: UserType) => {
    setActiveChatPartner(targetUser);
    setActiveModule('chat');
  };

  const renderModule = () => {
    switch (activeModule) {
      case 'feed':
        return <Feed externalPosts={posts} onAddPost={handleAddPost} />;
      case 'chat':
        return (
          <Chat 
            activePartner={activeChatPartner} 
            onUpdateBalance={updateBalance} 
            messagesByThread={messagesByThread}
            onSendMessage={(threadId, msg) => {
              setMessagesByThread(prev => ({
                ...prev,
                [threadId]: [...(prev[threadId] || []), msg]
              }));
            }}
          />
        );
      case 'gathering':
        return <Gathering onStartChat={handleStartChat} />;
      case 'wallet':
        return <Wallet balance={user.balance} onAddFunds={() => updateBalance(50)} />;
      case 'pilot':
        return <Pilot />;
      case 'profile':
        return <Profile user={user} onLogout={() => {
          localStorage.removeItem('ekan_user_session');
          setIsLoggedIn(false);
          setUser(INITIAL_USER);
        }} />;
      case 'scanner':
        return <Scanner 
          onAddFriend={(friend) => setFriends(prev => [...prev, friend])} 
          onProcessPayment={(amt) => updateBalance(-amt)} 
        />;
      default:
        return <Feed externalPosts={posts} onAddPost={handleAddPost} />;
    }
  };

  return (
    <>
      {!isLoggedIn ? (
        <Auth onComplete={handleOnboardingComplete} />
      ) : (
        <Layout activeModule={activeModule} setActiveModule={(m) => {
          if (m !== 'chat') setActiveChatPartner(null);
          setActiveModule(m);
        }}>
          <div className="max-w-3xl mx-auto h-full border-x border-white/5 bg-[#050505]/40 backdrop-blur-3xl shadow-2xl relative">
            {renderModule()}
            <div className="absolute top-4 right-4 pointer-events-none z-[100] hidden sm:block">
              <div className="bg-white/5 border border-white/10 backdrop-blur-md px-3 py-1.5 rounded-full flex items-center space-x-2">
                <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-gray-400">Diag: Grid Connected</span>
              </div>
            </div>
          </div>
        </Layout>
      )}
    </>
  );
};

export default App;

