                <div className="absolute top-6 right-6 bg-white/10 backdrop-blur-2xl px-5 py-2.5 rounded-full text-[10px] uppercase font-black tracking-[0.3em] border border-white/20 text-gold shadow-2xl">
                    {news.source}
