  const [user, setUser] = useState<UserProfile>(INITIAL_USER);
  const [activeChatPartner, setActiveChatPartner] = useState<UserType | null>(null);

  // Persistence State - Mocking a Backend DB
  const [posts, setPosts] = useState<Post[]>([]);
  const [messagesByThread, setMessagesByThread] = useState<Record<string, Message[]>>({});
  const [friends, setFriends] = useState<UserType[]>([]);

  // Session Recovery Diagnostic
  useEffect(() => {
    const saved = localStorage.getItem('ekan_production_session_v4');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setUser(parsed.user || INITIAL_USER);
        setPosts(parsed.posts || []);
        setMessagesByThread(parsed.messages || {});
        setFriends(parsed.friends || []);
        setIsLoggedIn(true);
      } catch (e) {
        console.error("Diagnostic Error: Session terminal corrupted.");
      }
    }
  }, []);

  // Save state to simulate DB synchronization
  useEffect(() => {
    if (isLoggedIn) {
      localStorage.setItem('ekan_production_session_v4', JSON.stringify({
        user, posts, messages: messagesByThread, friends
      }));
    }
  }, [user, posts, messagesByThread, friends, isLoggedIn]);

  const handleOnboardingComplete = (data: { name: string; email: string; interests: string[]; location: string }) => {
    const newUser = {
      ...user,
      name: data.name,
      email: data.email,
      location: data.location,
      handle: `@${data.name.toLowerCase().replace(/\s+/g, '_')}`,
      interests: data.interests,
      balance: 3500.00 // Global Launch Bonus
    };
    setUser(newUser);
    setIsLoggedIn(true);
  };

  const updateBalance = (amount: number) => {
    setUser(prev => ({ ...prev, balance: Math.max(0, prev.balance + amount) }));
  };

  const handleAddPost = (content: string) => {
    const newPost: Post = {
      id: Date.now().toString(),
      thumbnail: `https://picsum.photos/seed/${Math.random()}/800/600`,
      likes: 0,
      authorName: user.name,
      content,
      timestamp: 'Just now'
    };
    setPosts([newPost, ...posts]);
  };

  const handleSendMessage = (threadId: string, msg: Message) => {
    setMessagesByThread(prev => ({
      ...prev,
      [threadId]: [...(prev[threadId] || []), msg]
    }));
  };

  const handleAddFriend = (friend: UserType) => {
    setFriends(prev => {
      if (prev.find(f => f.id === friend.id)) return prev;
      return [...prev, friend];
    });
  };

  const renderModule = () => {
    switch (activeModule) {
      case 'feed':
        return <Feed externalPosts={posts} onAddPost={handleAddPost} />;
      case 'chat':
        return (
          <Chat 
            activePartner={activeChatPartner} 
            onUpdateBalance={updateBalance}
            messagesByThread={messagesByThread}
            onSendMessage={handleSendMessage}
          />
        );
      case 'gathering':
        return <Gathering onStartChat={(u) => { setActiveChatPartner(u); setActiveModule('chat'); }} />;
      case 'wallet':
        return <Wallet balance={user.balance} onAddFunds={updateBalance} />;
      case 'pilot':
        return <Pilot />;
      case 'profile':
        return <Profile user={user} onLogout={() => { localStorage.removeItem('ekan_production_session_v4'); setIsLoggedIn(false); setUser(INITIAL_USER); }} />;
      case 'scanner':
        return <Scanner onAddFriend={handleAddFriend} onProcessPayment={(amt) => updateBalance(-amt)} />;
      default:
        return <Feed externalPosts={posts} onAddPost={handleAddPost} />;
    }
  };

  return (
    <>
      {!isLoggedIn ? (
        <Auth onComplete={handleOnboardingComplete} />
      ) : (
        <Layout activeModule={activeModule} setActiveModule={setActiveModule}>
          <div className="max-w-5xl mx-auto h-full border-x border-white/5 bg-[#050505]/60 backdrop-blur-[40px] shadow-[0_40px_100px_rgba(0,0,0,1)] relative overflow-hidden">
            {renderModule()}
            {/* Immersive HUD Overlay */}
            <div className="absolute top-6 right-8 pointer-events-none z-[100] hidden lg:block">
              <div className="bg-white/5 border border-white/10 backdrop-blur-2xl px-6 py-2.5 rounded-full flex items-center space-x-4 shadow-2xl">
                <div className="flex items-center space-x-1.5">
                  <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(34,197,94,0.6)]"></div>
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] text-white">Grid Online</span>
                </div>
                <div className="h-4 w-[1px] bg-white/10"></div>
                <span className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">{user.location} Node</span>
              </div>
            </div>
          </div>
        </Layout>
      )}
    </>
  );
};

